    31	  struct Qual
    32	  {
    33	    bool const_{ false };
    34	    // bool volatile_{ false };
    35	
    36	    bool operator==(const Qual& other) const { return const_ == other.const_; }
    37	    bool operator!=(const Qual& other) const { return !operator==(other); }
    38	  };
    39	
    40	  Spec spec{ Spec::kINVALID };
    41	  Qual qual;
