    45	  /**
    46	   * @brief 类型等价性判断，等价性是类型系统最重要的性质，我们在这里而不是
    47	   * 在 Typing 中实现。
    48	   */
    49	  bool operator==(const Type& other) const;
    50	  bool operator!=(const Type& other) const { return !operator==(other); }
    51	
    52	private:
    53	  void __mark__(Mark mark) override;
    54	
    55	public:
    56	  /**
    57	   * @brief 类型缓存
    58	   *
    59	   * 编译过程中，尤其是语法分析和类型推导阶段，会有大量的语义节点包含相同的
    60	   * 类型或子类型，重复创建这些类型节点会导致无谓的内存占用，因此使用这个类
    61	   * 型缓存器。考虑到我们测例中不会包含太多的类型种类，这里的实现采用了简单
    62	   * 的线性查找算法，更高级的做法是设计有唯一性的类型编码方法，然后使用哈希
    63	   * 表来映射和查找。
    64	   */
    65	  struct Cache : std::vector<const Type*>
    66	  {
    67	    Obj::Mgr& mMgr;
    68	
    69	    Cache(Obj::Mgr& mgr)
    70	      : mMgr(mgr)
    71	    {
    72	    }
    73	
    74	    const Type* operator()(Spec spec, Qual qual, TypeExpr* texp);
    75	  };
    76	};
