    78	struct TypeExpr : Obj
    79	{
    80	  TypeExpr* sub{ nullptr };
    81	
    82	  bool operator==(const TypeExpr& other) const
    83	  {
    84	    if (this == &other)
    85	      return true;
    86	    if (this == nullptr || &other == nullptr)
    87	      return false;
    88	    return __equal__(other);
    89	  }
    90	
    91	  bool operator!=(const TypeExpr& other) const { return !operator==(other); }
    92	
    93	protected:
    94	  void __mark__(Mark mark) override;
    95	
    96	private:
    97	  virtual bool __equal__(const TypeExpr& other) const = 0;
    98	};
